class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars are no longer treated as unset.
        // GetEnvironmentVariable now returns "" instead of null for empty vars.
        // Use a helper that checks both null and empty to detect "not set".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        // val == "" means explicitly set to empty (preserved on .NET 9)
    }
}

